# Custom class: define __hash__ consistent with __eq__
class Point:
    def __init__(self, x, y):
        self.x, self.y = x, y

    def __eq__(self, other):
        return isinstance(other, Point) and self.x == other.x and self.y == other.y

    def __hash__(self):
        # hash must be consistent with __eq__
        # Use tuple hash — stable and fast
        return hash((self.x, self.y))

p1 = Point(1, 2)
p2 = Point(1, 2)
print(p1 == p2)         # True
print(hash(p1) == hash(p2))  # True — contract satisfied
print({p1, p2})         # {Point(1,2)} — treated as same element
print({p1: 'origin'})   # works — hashable

# Gotcha: defining __eq__ alone makes class unhashable
class BadPoint:
    def __eq__(self, other): return True
    # __hash__ is implicitly set to None by Python

try:
    hash(BadPoint())   # TypeError: unhashable type: 'BadPoint'
except TypeError as e:
    print(e)
